import { invoke } from "@tauri-apps/api/core";
export function listInstalledSkills() {
    return invoke("list_installed_skills");
}
export function listRecognizedSkills() {
    return invoke("list_recognized_skills");
}
export function installSkill(skill) {
    return invoke("install_skill", {
        payload: {
            id: skill.id,
            name: skill.name,
            category: skill.category,
            summary: skill.summary,
            author: skill.author,
        },
    });
}
export function removeSkill(skillId) {
    return invoke("remove_skill", {
        skillId,
    });
}
